let source = 'unknown';
let command = '';
let isAgentMode = false;

try { if ($('⏰ Tick cada 15min').first()) source = 'tick'; } catch(e){}
try { if ($('⏰ Outreach 9AM COL').first()) source = 'outreach_load'; } catch(e){}
try { if ($('⏰ Reporte 1PM COL').first()) source = 'report'; } catch(e){}
try {
  const trigger = $('🔌 Execute Workflow Trigger').first();
  if (trigger) {
    source = 'external';
    const input = trigger.json;
    command = input.command || input.query || input.message || input.instruction || '';
    isAgentMode = command.length > 0;
  }
} catch(e){}

return [{ json: {
  source, command, isAgentMode,
  timestamp: new Date().toISOString(),
  originalInput: (() => { try { return $('🔌 Execute Workflow Trigger').first().json; } catch(e) { return {}; } })()
}}];

const agentResponse = $input.first().json;
const originalInput = $('🎯 Construir Prompt Agente').first().json;

let response = {
  success: true, mode: 'agent',
  command: originalInput.command,
  response: agentResponse.output || agentResponse.text || 'Comando ejecutado',
  timestamp: new Date().toISOString()
};

if (agentResponse.intermediateSteps && agentResponse.intermediateSteps.length > 0) {
  response.toolsUsed = agentResponse.intermediateSteps.map(step => ({
    tool: step.action?.tool || 'unknown',
    input: step.action?.toolInput || '',
    result: step.observation || ''
  }));
}

return [{ json: response }];

const input = $input.first().json;
let textResponse = input.response || input.output || input.message || 'Comando ejecutado';
if (input.toolsUsed && input.toolsUsed.length > 0) {
  const ts = input.toolsUsed.map(t => `${t.tool}: ${(t.result||'OK').substring(0,100)}`).join('\n');
  textResponse += `\n\n📋 Acciones:\n${ts}`;
}
return [{ json: {
  text: textResponse, textResponse,
  channel: 'instagram_agent', userPhone: '573124348669', userName: 'Santiago',
  messageId: `agent-${Date.now()}`, toolResponse: JSON.stringify(input.toolsUsed||[]),
  remoteJid: '573124348669@s.whatsapp.net', chatId: '573124348669',
  messageType: 'agent_response', 'message.chat.id': '573124348669', 'message.text': textResponse
}}];

const leads = $input.all();
const tasks = [];
for (const item of leads) {
  const lead = item.json;
  const pn = (lead.Nombre||'emprendedor').split(' ')[0];
  const ap = [`Hola ${pn}, vi lo que haces con ${lead.Negocio||'tu negocio'}`,`Ei ${pn}! Me cruzé con tu perfil`,`Hey ${pn}, qué interesante lo de ${lead.Negocio||'tu negocio'}`];
  const ci = ['¿Tienes 20 min esta semana?','¿Estarías abierto a una llamada rápida?','¿Podemos agendar 20 minuticos?'];
  tasks.push({type:'dm_outreach',priority:lead.Prioridad==='alta'?1:2,payload:{instagramUrl:lead.Instagram||'',mensaje:`${ap[Math.floor(Math.random()*3)]} — tengo algo que podría ayudarte. ${ci[Math.floor(Math.random()*3)]}`,leadData:{nombre:lead.Nombre,rowIndex:lead.row_number,negocio:lead.Negocio}},createdAt:Date.now(),status:'pending'});
}
tasks.push({type:'check_inbox',priority:1,payload:{maxThreads:20},createdAt:Date.now(),status:'pending'});
tasks.push({type:'engagement_likes',priority:3,payload:{maxLikes:15},createdAt:Date.now(),status:'pending'});
tasks.push({type:'check_followup',priority:2,payload:{daysWithoutReply:2},createdAt:Date.now(),status:'pending'});
return [{json:{tasks,totalTasks:tasks.length}}];

const keysRaw = $input.first().json;
const keys = keysRaw.value || keysRaw.keys || [];
if (!keys || keys.length === 0) return [{json:{hasTasks:false,reason:'Cola vacía'}}];
keys.sort();
return [{json:{hasTasks:true,queueKey:keys[0],totalQueues:keys.length}}];

const raw = $input.first().json;
let tasks = [];
try { const str = raw.value||raw; tasks = typeof str==='string' ? JSON.parse(str) : str; } catch(e) { return [{json:{hasTasks:false,error:'Parse error'}}]; }
const pending = tasks.filter(t=>t.status==='pending').sort((a,b)=>(a.priority||99)-(b.priority||99));
if (pending.length===0) return [{json:{hasTasks:false,reason:'Todas completadas'}}];
